import { Schema } from "effect";

export type RelaySchema<A> = Schema.Schema<A>;

export const emptyArgs = <A extends []>(): RelaySchema<A> => Schema.Tuple([]) as unknown as RelaySchema<A>;

export const ipcArgs = <A extends readonly unknown[]>(items: ReadonlyArray<Schema.Top>): RelaySchema<A> =>
  Schema.Tuple(items) as unknown as RelaySchema<A>;

export const ipcString = Schema.String;
export const ipcUnknown = Schema.Unknown;
export const ipcObject = Schema.Record(Schema.String, Schema.Unknown) as RelaySchema<Record<string, unknown>>;
export const ipcOptionalUnknown = Schema.optional(Schema.Unknown) as Schema.Top;

export const ipcVoid = Schema.Void as RelaySchema<void>;

export const ipcResult = <A>(): RelaySchema<A> => Schema.Unknown as RelaySchema<A>;

import type {
  ClarificationAnswerInput,
  EpicSubticketCreateInput,
  EpicSubticketLinkInput,
  EpicSubticketUnlinkInput,
  TicketCreateInput,
  TicketDraftResult,
  TicketMoveInput,
  TicketSaveInput
} from "../../../shared/types";
import {
  cancelTicketUpdateRun,
  createTicketDraft,
  startTicketUpdateRun,
  ticketDraftErrorToPayload
} from "../../services/codex";
import { pathResolve } from "../../services/io";
import { logError, logWarn } from "../../services/logger";
import { fromPromise } from "../../services/runtime";
import {
  answerClarificationQuestion,
  createSubticket,
  createTicket,
  deleteTicket,
  duplicateTicket,
  isTicketNotFoundError,
  listTicketReferenceCandidates,
  linkSubticket,
  moveTicket,
  readClarificationQuestions,
  readTicket,
  revealTicketFile,
  saveTicket,
  unlinkSubticket
} from "../../services/storage";
import { defineRelayIpcMethod, type AnyRelayIpcMethod } from "../RelayIpc";
import { relayIpcChannels } from "../channels";
import { ipcArgs, ipcObject, ipcResult, ipcString, ipcVoid } from "../schema";

export const ticketIpcMethods = [
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketCreateDraft,
    payload: ipcArgs([ipcObject]),
    result: ipcResult(),
    handler: (_event, input) =>
      fromPromise(async (): Promise<TicketDraftResult> => {
        try {
          return { ok: true, draft: await createTicketDraft(input) };
        } catch (error) {
          return { ok: false, error: ticketDraftErrorToPayload(error) };
        }
      })
  }),
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketCreateManual,
    payload: ipcArgs([ipcString, ipcObject]),
    result: ipcResult(),
    handler: (_event, projectPath: string, input: TicketCreateInput) => fromPromise(() => createTicket(projectPath, input))
  }),
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketCreateSubticket,
    payload: ipcArgs([ipcObject]),
    result: ipcResult(),
    handler: (_event, input: EpicSubticketCreateInput) => fromPromise(() => createSubticket(input))
  }),
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketLinkSubticket,
    payload: ipcArgs([ipcObject]),
    result: ipcResult(),
    handler: (_event, input: EpicSubticketLinkInput) =>
      fromPromise(() => linkSubticket(input.projectPath, input.epicId, input.ticketId))
  }),
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketUnlinkSubticket,
    payload: ipcArgs([ipcObject]),
    result: ipcResult(),
    handler: (_event, input: EpicSubticketUnlinkInput) =>
      fromPromise(() => unlinkSubticket(input.projectPath, input.epicId, input.ticketId))
  }),
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketStartAgentUpdate,
    payload: ipcArgs([ipcObject]),
    result: ipcResult(),
    handler: (_event, input) => fromPromise(() => startTicketUpdateRun(input))
  }),
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketCancelAgentUpdate,
    payload: ipcArgs([ipcString]),
    result: ipcVoid,
    handler: (_event, runId: string) => fromPromise(() => cancelTicketUpdateRun(runId))
  }),
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketReferences,
    payload: ipcArgs([ipcString]),
    result: ipcResult(),
    handler: (_event, projectPath: string) => fromPromise(() => listTicketReferenceCandidates(projectPath))
  }),
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketRead,
    payload: ipcArgs([ipcString, ipcString]),
    result: ipcResult(),
    handler: (_event, projectPath: string, ticketId: string) =>
      fromPromise(async () => {
        const resolvedProjectPath = pathResolve(projectPath);
        try {
          return await readTicket(resolvedProjectPath, ticketId);
        } catch (error) {
          const meta = { projectPath: resolvedProjectPath, ticketId };
          if (isTicketNotFoundError(error)) {
            await logWarn("ticket:read", "ticket file missing", { ...meta, filePath: error.filePath });
          } else {
            await logError("ticket:read", "ticket read failed", error, meta);
          }
          throw error;
        }
      })
  }),
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketSave,
    payload: ipcArgs([ipcObject]),
    result: ipcResult(),
    handler: (_event, input: TicketSaveInput) => fromPromise(() => saveTicket(input))
  }),
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketMove,
    payload: ipcArgs([ipcObject]),
    result: ipcResult(),
    handler: (_event, input: TicketMoveInput) => fromPromise(() => moveTicket(input))
  }),
  defineRelayIpcMethod({
    channel: relayIpcChannels.ticketClarifications,
