import { Context, Effect, Layer } from "effect";
import type { AppRegistry } from "../../../shared/types";
import { getElectronPath } from "../../electron";
import { fromPromise, runBackendEffect } from "../runtime";
import { makeDirectoryEffect, pathDirname, pathJoin, pathResolve, readTextFileEffect, renamePathEffect, writeTextFileEffect } from "../io";
import { appRegistrySchema } from "../schemas";

const defaultRegistry = (): AppRegistry => ({
  schemaVersion: 1,
  projects: [],
  ui: {
    lastProjectPath: null,
    theme: "system"
  }
});

const registryPath = (): string => pathJoin(getElectronPath("userData"), "registry.json");

const readRegistryPromise = async (): Promise<AppRegistry> => {
  try {
    const raw = await runBackendEffect(readTextFileEffect(registryPath()));
    return appRegistrySchema.parse(JSON.parse(raw)) as AppRegistry;
  } catch {
    return defaultRegistry();
  }
};

const writeRegistryPromise = async (registry: AppRegistry): Promise<void> => {
  const target = registryPath();
  await runBackendEffect(makeDirectoryEffect(pathDirname(target)));
  const tmp = `${target}.tmp`;
  await runBackendEffect(writeTextFileEffect(tmp, `${JSON.stringify(registry, null, 2)}\n`));
  await runBackendEffect(renamePathEffect(tmp, target));
};

const upsertProjectPathPromise = async (projectPath: string): Promise<AppRegistry> => {
  const registry = await readRegistryPromise();
  const resolved = pathResolve(projectPath);
  const existing = registry.projects.find((project) => pathResolve(project.path) === resolved);
  const now = new Date().toISOString();

  if (existing) {
    existing.lastOpenedAt = now;
  } else {
    registry.projects.push({
      path: resolved,
      pinned: true,
      lastOpenedAt: now,
      sidebarPosition: (registry.projects.at(-1)?.sidebarPosition ?? 0) + 1000
    });
  }

  registry.ui.lastProjectPath = resolved;
  await writeRegistryPromise(registry);
  return registry;
};

const removeProjectPathPromise = async (projectPath: string): Promise<AppRegistry> => {
  const registry = await readRegistryPromise();
  const resolved = pathResolve(projectPath);
  registry.projects = registry.projects.filter((project) => pathResolve(project.path) !== resolved);
  if (registry.ui.lastProjectPath && pathResolve(registry.ui.lastProjectPath) === resolved) {
    registry.ui.lastProjectPath = registry.projects[0]?.path ?? null;
  }
  await writeRegistryPromise(registry);
  return registry;
};

export type RegistryStoreService = {
  readonly read: () => Effect.Effect<AppRegistry, unknown>;
  readonly write: (registry: AppRegistry) => Effect.Effect<void, unknown>;
  readonly upsertProjectPath: (projectPath: string) => Effect.Effect<AppRegistry, unknown>;
  readonly removeProjectPath: (projectPath: string) => Effect.Effect<AppRegistry, unknown>;
};

export const RegistryStore = Context.Service<RegistryStoreService>("relay/RegistryStore");

export const RegistryStoreLive = Layer.succeed(RegistryStore)({
  read: () => fromPromise(() => readRegistryPromise()),
  write: (registry) => fromPromise(() => writeRegistryPromise(registry)),
  upsertProjectPath: (projectPath) => fromPromise(() => upsertProjectPathPromise(projectPath)),
  removeProjectPath: (projectPath) => fromPromise(() => removeProjectPathPromise(projectPath))
});

export const readRegistry = (): Promise<AppRegistry> =>
  runBackendEffect(Effect.provide(RegistryStore.use((store) => store.read()), RegistryStoreLive));

export const writeRegistry = (registry: AppRegistry): Promise<void> =>
  runBackendEffect(Effect.provide(RegistryStore.use((store) => store.write(registry)), RegistryStoreLive));

export const upsertProjectPath = (projectPath: string): Promise<AppRegistry> =>
  runBackendEffect(Effect.provide(RegistryStore.use((store) => store.upsertProjectPath(projectPath)), RegistryStoreLive));

export const removeProjectPath = (projectPath: string): Promise<AppRegistry> =>
  runBackendEffect(Effect.provide(RegistryStore.use((store) => store.removeProjectPath(projectPath)), RegistryStoreLive));

import { Context, Effect, Layer } from "effect";
import type { RelayCodexEvent, RendererRunEvent } from "../../../shared/types";
import { RelayWindow } from "../../window/RelayWindow";
import { type BackendServices, fromPromise, runBackendEffect } from "../runtime";
import { appendTextFileEffect, isFileNotFoundError, makeDirectoryEffect, pathDirname, pathJoin, readTextFileEffect } from "../io";
import { runsPath } from "../storage";

export type RendererRunEventSink = {
  readonly emit: (event: RendererRunEvent) => void | Promise<void>;
};

export type RunEventSinkService = {
  readonly emit: (
    projectPath: string,
    ticketId: string,
    runId: string,
    threadId: string,
    event: RelayCodexEvent
  ) => Effect.Effect<void, unknown, BackendServices | Context.Service.Identifier<typeof RelayWindow>>;
};

export const RunEventSink = Context.Service<RunEventSinkService>("relay/RunEventSink");

export const rendererRunEventFromRelayEvent = (
  projectPath: string,
  ticketId: string,
  runId: string,
  event: RelayCodexEvent
): RendererRunEvent => ({
  ...event,
  projectPath,
  ticketId,
  runId
});

export const writeRunLogEffect = (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Effect.Effect<void, unknown, BackendServices> =>
  Effect.gen(function*() {
    const filePath = pathJoin(runsPath(projectPath), ticketId, `${runId}.jsonl`);
    yield* makeDirectoryEffect(pathDirname(filePath));
    const { type, timestamp, ...payload } = event;
    yield* appendTextFileEffect(
      filePath,
      `${JSON.stringify({
        schemaVersion: 1,
        timestamp,
        ticketId,
        runId,
        threadId,
        type,
        payload
      })}\n`
    );
  });

export const writeRunLog = (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Promise<void> => runBackendEffect(writeRunLogEffect(projectPath, ticketId, runId, threadId, event));

export const emitRunEventEffect = (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Effect.Effect<void, unknown, BackendServices | Context.Service.Identifier<typeof RelayWindow>> =>
  Effect.gen(function*() {
    yield* writeRunLogEffect(projectPath, ticketId, runId, threadId, event);
    const relayWindow = yield* RelayWindow;
    yield* relayWindow.sendRunEvent(rendererRunEventFromRelayEvent(projectPath, ticketId, runId, event));
  });

export const RunEventSinkLive = Layer.succeed(RunEventSink)({
  emit: emitRunEventEffect
});

export const emitRunEvent = (
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Promise<void> => runBackendEffect(RunEventSink.use((sink) => sink.emit(projectPath, ticketId, runId, threadId, event)));

export const emitRunEventToRendererSink = (
  rendererSink: RendererRunEventSink,
  projectPath: string,
  ticketId: string,
  runId: string,
  threadId: string,
  event: RelayCodexEvent
): Promise<void> =>
  runBackendEffect(
    Effect.gen(function*() {
      yield* writeRunLogEffect(projectPath, ticketId, runId, threadId, event);
      yield* fromPromise(() => Promise.resolve(rendererSink.emit(rendererRunEventFromRelayEvent(projectPath, ticketId, runId, event))));
    })
  );

export const readRunEvents = async (projectPath: string, ticketId: string, runId: string): Promise<RendererRunEvent[]> => {
  const filePath = pathJoin(runsPath(projectPath), ticketId, `${runId}.jsonl`);
  let raw = "";
  try {
    raw = await runBackendEffect(readTextFileEffect(filePath));
  } catch (error) {
    if (isFileNotFoundError(error)) return [];
    throw error;
  }

  return raw
    .split("\n")
    .filter(Boolean)
    .map((line) => {
      const parsed = JSON.parse(line) as {
        timestamp: string;
        ticketId: string;
        runId: string;
        threadId: string;
        type: RelayCodexEvent["type"];
        payload: Record<string, unknown>;
      };
      return {
        ...parsed.payload,
        type: parsed.type,
        timestamp: parsed.timestamp,
        projectPath,
        ticketId: parsed.ticketId,
        runId: parsed.runId
      } as RendererRunEvent;
    });
};

import { Context, Effect, Layer } from "effect";
import type { GitMetadata } from "../../../shared/types";
import { BackendConfig, fromPromise, runBackendEffect } from "../runtime";
import { CommandExecutor, pathResolve, statPathEffect } from "../io";

export type GitCommandResult = {
  stdout: string;
  stderr: string;
};

export type GitCommandRunner = (projectPath: string, args: string[]) => Promise<GitCommandResult>;

type GitMetadataDependencies = {
  execGit?: GitCommandRunner;
  now?: () => string;
};

const defaultGitRunner: GitCommandRunner = (projectPath, args) =>
  runBackendEffect(
    CommandExecutor.use((executor) =>
      executor.execFile("git", ["-C", projectPath, ...args], {
        maxBuffer: 1024 * 1024,
        timeoutMs: 5_000
      })
    )
  );

const baseMetadata = (
  state: GitMetadata["state"],
  updatedAt: string,
  patch: Partial<Omit<GitMetadata, "state" | "updatedAt">> = {}
): GitMetadata => ({
  state,
  isGitRepository: false,
  branchName: null,
  isDetachedHead: false,
  commitSha: null,
  isDirty: false,
  changedFileCount: null,
  message: null,
  error: null,
  updatedAt,
  ...patch
});

const commandMessage = (error: unknown): string => {
  if (typeof error === "object" && error && "stderr" in error && typeof (error as { stderr?: unknown }).stderr === "string") {
    const stderr = (error as { stderr: string }).stderr.trim();
    if (stderr) return stderr.split("\n")[0];
  }
  if (error instanceof Error) return error.message;
  return "Git command failed.";
};

const isMissingGitBinary = (error: unknown): boolean =>
  typeof error === "object" && error !== null && "code" in error && (error as NodeJS.ErrnoException).code === "ENOENT";

const isNotGitRepositoryError = (error: unknown): boolean => /not a git repository|not a git dir/i.test(commandMessage(error));

const isUnbornHeadError = (error: unknown): boolean =>
  /needed a single revision|ambiguous argument 'HEAD'|unknown revision or path/i.test(commandMessage(error));

export const parsePorcelainChangedFileCount = (output: string): number => {
  const records = output.split("\0").filter((record) => record.length > 0);
  let count = 0;

  for (let index = 0; index < records.length; index += 1) {
    const record = records[index];
    if (record.length < 3) continue;
    count += 1;

    const stagedStatus = record[0];
    const unstagedStatus = record[1];
    if (stagedStatus === "R" || stagedStatus === "C" || unstagedStatus === "R" || unstagedStatus === "C") {
      index += 1;
    }
  }

  return count;
};

const readGitMetadataPromise = async (
  projectPath: string,
  dependencies: GitMetadataDependencies = {}
): Promise<GitMetadata> => {
  const resolved = pathResolve(projectPath);
  const execGit = dependencies.execGit ?? defaultGitRunner;
  const updatedAt = dependencies.now?.() ?? new Date().toISOString();

  try {
    const info = await runBackendEffect(statPathEffect(resolved));
    if (!info.isDirectory) {
      return baseMetadata("missing", updatedAt, {
        message: "Project path is not a directory."
      });
    }
  } catch (error) {
    return baseMetadata("missing", updatedAt, {
      message: error instanceof Error ? error.message : "Project path is unavailable.",
      error: error instanceof Error ? error.message : "Project path is unavailable."
    });
  }

  try {
    const insideWorkTree = (await execGit(resolved, ["rev-parse", "--is-inside-work-tree"])).stdout.trim();
    if (insideWorkTree !== "true") {
      return baseMetadata("not_git", updatedAt, {
        message: "Project path is not a Git repository."
      });
    }
  } catch (error) {
    if (isMissingGitBinary(error)) {
      return baseMetadata("unavailable", updatedAt, {
        message: "Git command is unavailable.",
        error: commandMessage(error)
      });
    }
    if (isNotGitRepositoryError(error)) {
      return baseMetadata("not_git", updatedAt, {
        message: "Project path is not a Git repository."
      });
    }
    return baseMetadata("error", updatedAt, {
      message: "Unable to inspect Git repository.",
      error: commandMessage(error)
    });
  }

  let branchName: string | null = null;
  let commitSha: string | null = null;

  try {
    branchName = (await execGit(resolved, ["branch", "--show-current"])).stdout.trim() || null;

    try {
      commitSha = (await execGit(resolved, ["rev-parse", "--short=8", "HEAD"])).stdout.trim() || null;
    } catch (error) {
      if (!isUnbornHeadError(error)) throw error;
    }

    const statusOutput = (await execGit(resolved, ["status", "--porcelain=v1", "-z", "--untracked-files=all"])).stdout;
    const changedFileCount = parsePorcelainChangedFileCount(statusOutput);
    const isDetachedHead = branchName === null && commitSha !== null;

    return baseMetadata("ready", updatedAt, {
      isGitRepository: true,
      branchName,
      isDetachedHead,
      commitSha,
      isDirty: changedFileCount > 0,
      changedFileCount,
      message: changedFileCount > 0 ? `${changedFileCount} uncommitted file change(s).` : "Working tree clean."
    });
  } catch (error) {
    if (isMissingGitBinary(error)) {
      return baseMetadata("unavailable", updatedAt, {
        message: "Git command is unavailable.",
        error: commandMessage(error)
      });
    }
    return baseMetadata("error", updatedAt, {
      isGitRepository: true,
      branchName,
      isDetachedHead: branchName === null && commitSha !== null,
      commitSha,
      message: "Unable to inspect Git repository.",
      error: commandMessage(error)
    });
  }
};

const gitMetadataCache = new Map<string, { value?: GitMetadata; expiresAt: number; pending?: Promise<GitMetadata> }>();

const readCachedGitMetadataPromise = async (
  projectPath: string,
  options: { force?: boolean; cacheTtlMs?: number } = {}
): Promise<GitMetadata> => {
  const resolved = pathResolve(projectPath);
  const cached = gitMetadataCache.get(resolved);
  const now = Date.now();

  if (!options.force && cached?.value && cached.expiresAt > now) {
    return cached.value;
  }
  if (!options.force && cached?.pending) {
    return cached.pending;
  }

  const pending = readGitMetadataPromise(resolved).then((value) => {
    gitMetadataCache.set(resolved, {
      value,
      expiresAt: Date.now() + (options.cacheTtlMs ?? 3_000)
    });
    return value;
  });

  gitMetadataCache.set(resolved, {
    value: cached?.value,
    expiresAt: cached?.expiresAt ?? 0,
    pending
  });

  return pending;
};

const clearGitMetadataCacheSync = (): void => {
  gitMetadataCache.clear();
};

export type GitServiceService = {
  readonly readMetadata: (projectPath: string, dependencies?: GitMetadataDependencies) => Effect.Effect<GitMetadata, unknown>;
  readonly readCachedMetadata: (
    projectPath: string,
    options?: { force?: boolean }
  ) => Effect.Effect<GitMetadata, unknown, Context.Service.Identifier<typeof BackendConfig>>;
  readonly clearCache: () => Effect.Effect<void>;
};

export const GitService = Context.Service<GitServiceService>("relay/GitService");

export const GitServiceLive = Layer.succeed(GitService)({
  readMetadata: (projectPath, dependencies = {}) => fromPromise(() => readGitMetadataPromise(projectPath, dependencies)),
  readCachedMetadata: (projectPath, options = {}) =>
    Effect.gen(function*() {
      const config = yield* BackendConfig;
      return yield* fromPromise(() => readCachedGitMetadataPromise(projectPath, { ...options, cacheTtlMs: config.gitMetadataCacheTtlMs }));
    }),
  clearCache: () => Effect.sync(clearGitMetadataCacheSync)
});

export const readGitMetadata = (projectPath: string, dependencies: GitMetadataDependencies = {}): Promise<GitMetadata> =>
  runBackendEffect(Effect.provide(GitService.use((service) => service.readMetadata(projectPath, dependencies)), GitServiceLive));

export const readCachedGitMetadata = (projectPath: string, options: { force?: boolean } = {}): Promise<GitMetadata> =>
  runBackendEffect(Effect.provide(GitService.use((service) => service.readCachedMetadata(projectPath, options)), GitServiceLive));

export const clearGitMetadataCache = (): void => {
  clearGitMetadataCacheSync();
};

import test from "node:test";
import assert from "node:assert/strict";
import { Effect, Schema } from "effect";
import { makeRelayIpcService, type AnyRelayIpcMethod } from "../src/main/ipc/RelayIpc";
import { relayIpcMethods } from "../src/main/ipc/methods";
import { ipcArgs, ipcString } from "../src/main/ipc/schema";
import type { ElectronIpcInvokeHandler, ElectronIpcService } from "../src/main/electron";
import { relayIpcChannels, type RelayIpcChannel } from "../src/shared/ipc";

const runTestEffect = <A, E, R>(effect: Effect.Effect<A, E, R>): Promise<A> =>
  Effect.runPromise(effect as Effect.Effect<A, E, never>);

test("typed IPC contract has exactly one schema-backed method for every channel", () => {
  const channels = Object.values(relayIpcChannels) as RelayIpcChannel[];
  const methodChannels = relayIpcMethods.map((method) => method.channel);

  assert.deepEqual([...methodChannels].sort(), [...channels].sort());
  assert.equal(new Set(methodChannels).size, channels.length);
  for (const channel of channels) {
    const method = relayIpcMethods.find((candidate) => candidate.channel === channel);
    assert.equal(typeof method?.handler, "function", `${channel} handler is registered`);
    assert.ok(method?.payload, `${channel} payload schema is registered`);
    assert.ok(method?.result, `${channel} result schema is registered`);
  }
});

test("RelayIpc registers, replaces, decodes, encodes, and removes handlers", async () => {
  const handlers = new Map<string, ElectronIpcInvokeHandler>();
  const removed: string[] = [];
  const electronIpc: ElectronIpcService = {
    handle: (channel, handler) =>
      Effect.sync(() => {
        handlers.set(channel, handler);
      }),
    removeHandler: (channel) =>
      Effect.sync(() => {
        removed.push(channel);
        handlers.delete(channel);
      })
  };
  const relayIpc = makeRelayIpcService(electronIpc, runTestEffect);
  const channel = relayIpcChannels.projectsRead;
  const method = (label: string): AnyRelayIpcMethod => ({
    channel,
    payload: ipcArgs<[string]>([ipcString]),
    result: Schema.String,
    handler: (_event, projectPath) => Effect.succeed(`${label}:${projectPath}`)
  });

  await Effect.runPromise(relayIpc.handle(method("first")));
  assert.equal(await handlers.get(channel)?.({}, "/tmp/relay"), "first:/tmp/relay");

  await Effect.runPromise(relayIpc.handle(method("second")));
  assert.equal(await handlers.get(channel)?.({}, "/tmp/relay"), "second:/tmp/relay");
  assert.deepEqual(removed, [channel, channel]);

  await Effect.runPromise(Effect.scoped(relayIpc.handleScoped(method("scoped"))));
  assert.equal(handlers.has(channel), false);
});

test("RelayIpc rejects invalid payloads before domain handlers run", async () => {
  let called = false;
  const handlers = new Map<string, ElectronIpcInvokeHandler>();
  const electronIpc: ElectronIpcService = {
    handle: (channel, handler) =>
      Effect.sync(() => {
        handlers.set(channel, handler);
      }),
    removeHandler: (channel) =>
      Effect.sync(() => {
        handlers.delete(channel);
      })
  };
  const relayIpc = makeRelayIpcService(electronIpc, runTestEffect);
  const method: AnyRelayIpcMethod = {
    channel: relayIpcChannels.projectsRead,
    payload: ipcArgs<[string]>([ipcString]),
    result: Schema.String,
    handler: () => {
      called = true;
      return Effect.succeed("ok");
    }
  };

  await Effect.runPromise(relayIpc.handle(method));
  await assert.rejects(() => handlers.get(method.channel)?.({}, 123) as Promise<unknown>);
  assert.equal(called, false);
});

};

const readTicketFile = async (filePath: string): Promise<TicketRecord> => {
  const raw = await runBackendEffect(readTextFileEffect(filePath));
  const parsed = matter(raw);
  const frontMatter = ticketFrontMatterSchema.parse(parsed.data) as TicketFrontMatter;
  return {
    frontMatter,
    markdown: parsed.content.trimStart(),
    filePath
  };
};

const readTickets = async (
  projectPath: string,
  columns: RelayColumn[]
): Promise<{ tickets: TicketSummary[]; records: TicketRecord[]; invalidTickets: InvalidTicket[] }> => {
  await runBackendEffect(makeDirectoryEffect(ticketsPath(projectPath)));
  const entries = await runBackendEffect(readDirectoryEffect(ticketsPath(projectPath)));
  const validColumnIds = new Set(columns.map((column) => column.id));
  const tickets: TicketSummary[] = [];
  const records: TicketRecord[] = [];
  const invalidTickets: InvalidTicket[] = [];

  for (const entry of entries) {
    if (!entry.endsWith(".md")) continue;
    const filePath = pathJoin(ticketsPath(projectPath), entry);
    const info = await runBackendEffect(statPathEffect(filePath));
    if (!info.isFile) continue;
    try {
      const record = await readTicketFile(filePath);
      if (!validColumnIds.has(record.frontMatter.status)) {
        invalidTickets.push({ filePath, reason: `Unknown status: ${record.frontMatter.status}` });
        continue;
      }
      records.push(record);
      tickets.push({
        ...record.frontMatter,
        excerpt: extractExcerpt(record.markdown),
        filePath
      });
    } catch (error) {
      invalidTickets.push({
        filePath,
        reason: error instanceof Error ? error.message : "Unable to parse ticket."
      });
    }
  }

  tickets.sort((a, b) => {
    if (a.status !== b.status) return a.status.localeCompare(b.status);
    return a.position - b.position;
  });

  return { tickets, records, invalidTickets };
};

export const readBoard = async (projectPath: string, lastOpenedAt?: string): Promise<BoardSnapshot> => {
  const resolved = resolveProjectPath(projectPath);
  const project = await summarizeProject(resolved, lastOpenedAt);

  if (!project.exists || !project.relayInitialized) {
    return {
      project,
      config: null,
      columns: DEFAULT_COLUMNS.map((column) => ({ ...column })),
      tickets: [],
      invalidTickets: []
    };
  }

  const config = await readProjectConfig(resolved);
  const { tickets, invalidTickets } = await readTickets(resolved, config.columns);
  return {
    project,
    config,
    columns: [...config.columns].sort((a, b) => a.position - b.position),
    tickets,
    invalidTickets
  };
};

const uniqueTicketIds = (ticketIds: string[]): string[] => {
  const seen = new Set<string>();
  const unique: string[] = [];
  for (const ticketId of ticketIds) {
    const trimmed = ticketId.trim();
    if (!trimmed || seen.has(trimmed)) continue;
    seen.add(trimmed);
    unique.push(trimmed);
  }
  return unique;
};

const normalizeFrontMatterRelationships = (frontMatter: TicketFrontMatter): TicketFrontMatter => {
  const ticketType = frontMatter.ticketType ?? "task";
  return {
    ...frontMatter,
    ticketType,
    parentEpicId: ticketType === "epic" ? null : frontMatter.parentEpicId ?? null,
    subticketIds: ticketType === "epic" ? uniqueTicketIds(frontMatter.subticketIds ?? []) : []
  };
};

const assertRelationshipShape = (frontMatter: TicketFrontMatter): void => {
  if (frontMatter.parentEpicId && frontMatter.parentEpicId === frontMatter.id) {
    throw new Error("A ticket cannot be linked as its own epic.");
  }
  if (frontMatter.ticketType === "epic" && frontMatter.parentEpicId) {
    throw new Error("Nested epics are not supported.");
  }
  if (frontMatter.ticketType === "task" && frontMatter.subticketIds.length > 0) {
    throw new Error("Only epic tickets can own subtickets.");
  }
  if (frontMatter.ticketType === "epic" && frontMatter.subticketIds.includes(frontMatter.id)) {
    throw new Error("An epic cannot include itself as a subticket.");
  }
};

const relativeMarkdownPath = (fromDirectory: string, toFile: string): string => {
  const relativePath = slashPath(pathRelative(fromDirectory, toFile));
  if (relativePath.startsWith(".") || relativePath.startsWith("/")) return relativePath;
  return `./${relativePath}`;
};

export const listTicketReferenceCandidates = async (projectPath: string): Promise<TicketReferenceCandidate[]> => {
  const resolvedProjectPath = resolveProjectPath(projectPath);
  const config = await readProjectConfig(resolvedProjectPath);
  const columnNames = new Map(config.columns.map((column) => [column.id, column.name]));
  const columnPositions = new Map(config.columns.map((column) => [column.id, column.position]));
  const { tickets } = await readTickets(resolvedProjectPath, config.columns);
  const ticketDirectory = ticketsPath(resolvedProjectPath);

  return [...tickets]
    .sort((a, b) => {
      const columnDelta = (columnPositions.get(a.status) ?? Number.MAX_SAFE_INTEGER) - (columnPositions.get(b.status) ?? Number.MAX_SAFE_INTEGER);
      if (columnDelta !== 0) return columnDelta;
      return a.position - b.position;
    })
    .map((ticket) => ({
      id: ticket.id,
      title: ticket.title,
      status: ticket.status,
      columnName: columnNames.get(ticket.status) ?? ticket.status,
      relativePath: slashPath(pathRelative(resolvedProjectPath, ticket.filePath)),
      linkPath: relativeMarkdownPath(ticketDirectory, ticket.filePath)
    }));
};

export const readTicket = async (projectPath: string, ticketId: string): Promise<TicketRecord> => {
  const resolvedProjectPath = resolveProjectPath(projectPath);
  const target = ticketPath(resolvedProjectPath, ticketId);
  try {
    return await readTicketFile(target);
  } catch (error) {
